INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Como saber se meu bebê está se desenvolvendo bem?', 'Ganha peso, faz cocô e xixi normalmente, interage com você. Se tudo isso está acontecendo, está tudo bem!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê fica olhando fixo para nada, é normal?', 'Sim! Bebês exploram o ambiente assim. Mas se fica MUITO tempo sem piscar, converse com o pediatra.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Quando bebê começa a brincar?', 'Desde pequeno! Recém-nascido já brinca com as mãozinhas. Depois vai pegando brinquedos, etc.', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('desenvolvimento', 'Meu bebê parece mais lento que outros, devo me preocupar?', 'Cada bebê tem seu ritmo! Não compara com outros. Se o pediatra disser que está tudo bem, está!', 'desenvolvimento', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Meu bebê caiu do sofá, o que faço?', 'Observa por 24h! Se ele vomita, fica inconsciente ou chora muito, vai para emergência. Geralmente bebê é resistente!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Bebê pode dormir com almofada?', 'Não! Antes de 1 ano, nada no berço. Só lençol mesmo.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Como deixar a casa segura para o bebê?', 'Tira objetos pequenos, protege tomadas, prende móveis na parede. Quando começar a engatinhar, fica mais atento!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Bebê pode usar chupeta?', 'Sim! Chupeta até reduz risco de morte súbita. Mas se ele não quer, não força.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Meu bebê engasgou, como fazer manobra de desengasgamento?', 'Se está tossindo, deixa tossir! Se não consegue respirar, coloca de bruços no seu antebraço e bate nas costas.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Bebê pode dormir na cama comigo?', 'Não é recomendado! Risco de morte súbita. Melhor berço do lado da cama.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Como proteger o bebê de quedas?', 'Nunca deixa sozinho em cama ou sofá. Sempre de olho! Quando engatinha, tira objetos perigosos.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Posso deixar bebê sozinho no berço?', 'Sim! Depois de alguns meses, pode deixar sozinho por curtos períodos. Mas sempre de olho!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Meu bebê caiu da cama, pode ter lesão interna?', 'Pode! Se caiu de altura, procura emergência para avaliação. Melhor prevenir!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Bebê pode usar travesseiro?', 'Não! Antes de 1 ano, nada no berço. Depois de 1 ano, travesseiro fino tudo bem.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Como saber se meu bebê tem lesão na cabeça?', 'Vomita, fica inconsciente, chora muito ou comportamento estranho. Se tiver esses sinais, vai para emergência!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Posso deixar bebê perto de animais de estimação?', 'Sim, mas com cuidado! Nunca deixa sozinho. Animais podem ser imprevisíveis.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Bebê pode brincar com brinquedo pequeno?', 'Não! Risco de engasgo. Brinquedos devem ser maiores que o punho do bebê.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Como evitar morte súbita?', 'Bebê de costas para dormir, sem almofada/cobertor, quarto fresco. Chupeta também ajuda!', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('seguranca', 'Meu bebê está com febre e caiu, devo me preocupar?', 'Sim! Procura o pediatra para avaliar. Febre + queda = observação importante.', 'seguranca', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Meu bebê ficou com febre depois da vacina, é normal?', 'Sim! Febre leve é resposta normal do corpo. Geralmente passa em 24-48h. Se for muito alta, procura o pediatra.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Posso dar remédio para febre depois da vacina?', 'Sim! Paracetamol ou ibuprofeno conforme a idade. Mas converse com o pediatra sobre a dose.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Qual é o calendário de vacinação?', 'Começa ao nascer com a BCG. Depois tem várias ao longo do primeiro ano. Seu pediatra te orienta!', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Meu bebê chorou muito depois da vacina, é normal?', 'Sim! Injeção dói, bebê chora. Depois passa! Abraça ele, consola.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Posso dar banho depois da vacina?', 'Sim! Banho morno ajuda até a relaxar. Sem problema!', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Meu bebê não fez a marquinha da BCG, é problema?', 'Nem sempre faz marquinha! Mas a vacina funcionou mesmo assim. Não se preocupa!', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Posso atrasar a vacina?', 'Melhor não! Mas se precisar, converse com o pediatra. Algumas vacinas têm intervalo mínimo.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Meu bebê ficou inchado depois da vacina, devo me preocupar?', 'Inchaço leve é normal. Passa em alguns dias. Se ficar muito grande, procura o pediatra.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Posso dar vacina se o bebê está resfriado?', 'Depende! Resfriado leve, pode dar. Febre alta, melhor esperar. Converse com o pediatra.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Quantas vacinas o bebê toma no primeiro ano?', 'Bastante! Mas é para proteger contra doenças graves. Confia no calendário!', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Vacina pode causar autismo?', 'Não! Isso é mito. Vacina não causa autismo. Milhões de bebês vacinados comprovam isso.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Meu bebê vomitou depois da vacina, é problema?', 'Pode ser reação à vacina ou coincidência. Se continuar vomitando, procura o pediatra.', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('vacinas', 'Posso dar duas vacinas no mesmo dia?', 'Sim! Seu pediatra faz isso normalmente. Não tem problema!', 'vacinas', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Estou muito cansada no pós-parto, é normal?', 'Sim! Seu corpo passou por muito! Dorme quando o bebê dorme. Pede ajuda para tarefas de casa.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Sinto tristeza depois que o bebê nasceu, tenho depressão pós-parto?', 'Pode ser! Mas também pode ser baby blues (tristeza leve que passa). Se durar mais de 2 semanas, procura o médico.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Meu cabelo está caindo muito, é normal?', 'Sim! Hormônios mudam depois do parto. Cabelo volta ao normal em alguns meses.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Quanto tempo dura o sangramento pós-parto?', 'Geralmente 4-6 semanas. Mas varia! Se durar muito ou tiver cheiro estranho, procura o médico.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Quando posso fazer exercício depois do parto?', 'Começa com exercícios leves depois de 6 semanas. Se foi cesárea, espera um pouco mais. Converse com o médico!', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Cesárea ainda dói muito, é normal?', 'Sim! Dor pode durar semanas. Toma o analgésico que o médico passou. Se piorar, procura o médico.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Sinto muita ansiedade depois que virei mãe, é normal?', 'Sim! Responsabilidade de mãe é grande mesmo! Tenta relaxar, respira fundo. Se ficar muito intensa, procura ajuda.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Meu corpo mudou muito, quando volta ao normal?', 'Leva tempo! Alguns meses. Mas seu corpo é INCRÍVEL por ter gerado um bebê! Respeita seu corpo.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Sinto tontura ao amamentar, é normal?', 'Pode ser! Amamentação às vezes causa queda de pressão. Senta confortavelmente, bebe água.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Meu peito dói muito, pode ser mastite?', 'Pode ser! Mastite é inflamação do peito. Procura o médico para tratar.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Quando posso voltar a trabalhar?', 'Depende da licença! Mas emocionalmente, quando se sentir pronta. Não tem pressa!', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Sinto culpa por querer voltar a trabalhar, é normal?', 'Sim! Mas trabalhar não te torna má mãe. Você pode ser mãe E ter carreira!', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Meu marido não me ajuda no pós-parto, como pedir?', 'Conversa com ele! Explica o que você precisa. Homem geralmente não sabe o que fazer, precisa de orientação.', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('saude_materna', 'Tenho vontade de sumir às vezes, é normal?', 'Sim! Maternidade é intensa. Mas se essa vontade é muito forte, procura ajuda profissional. Você não está sozinha!', 'saude_materna', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Quantas vezes devo dar banho no bebê?', 'Começa com 2-3 vezes por semana. Depois pode aumentar. Não precisa todos os dias!', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Qual é a temperatura ideal do banho?', 'Entre 37-38°C. Testa com o cotovelo! Se queimar, está muito quente.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'Como limpar o umbigo do recém-nascido?', 'Com álcool 70% e gaze limpa. Limpa ao redor do coto. Quando cair, só lava com água.', 'higiene', 'pt', 0, 'true');
INSERT INTO wilborKnowledgeBase (category, question, answerPt, keywords, kbLanguage, priority, isActive) VALUES ('higiene', 'O coto umbilical está sangrando, é perigoso?', 'Um pouco de sangue é normal. Mas se sangra muito, procura o pediatra.', 'higiene', 'pt', 0, 'true');